args.sparql:
SELECT ?event ?eventLabel WHERE { 
  VALUES ?femaleAthleticsEvent {
    wd:Q55248046 # women's javelin throw
    wd:Q55248094 # women's hammer throw
    wd:Q55248425 # women's weight throw
  }
  ?event wdt:P279* ?femaleAthleticsEvent .
  ?event wdt:P31/wdt:P279* wd:Q273027 . # instance of athletics event
  ?event wdt:P641 wd:Q242 . # taking place in Montserrat
  ?event wdt:P585 ?date .
  FILTER(?date >= "1982-01-01T00:00:00Z"^^xsd:dateTime && ?date < "1983-01-01T00:00:00Z"^^xsd:dateTime)
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en" }
}

SELECT DISTINCT ?eventLabel WHERE {
  VALUES ?sport {
    wd:Q55248046  # women's javelin throw
    wd:Q55248094  # women's hammer throw
    wd:Q55248425 # women's weight throw
  }
  ?event wdt:P31 ?sport.
  ?event wdt:P585 ?date.
  FILTER(YEAR(?date) = 1982)
  ?event rdfs:label ?eventLabel.
  FILTER(LANG(?eventLabel) = 'en')
  FILTER(CONTAINS(?eventLabel, 'Montserrat') OR CONTAINS(LCASE(?eventLabel), 'mon'))
}

