args.sparql:
SELECT DISTINCT ?sportLabel WHERE {
  ?sport wdt:P279* wd:Q184865 . # Hammer throw and its subclasses
  ?record wdt:P31 wd:Q16521 ; # Instance of sport record
          wdt:P1346 ?sport ;
          wdt:P585 ?date ;
          wdt:P710 ?athlete .
  ?athlete wdt:P21 wd:Q6581072 . # Female
  FILTER(YEAR(?date) = 1982)
  ?sport rdfs:label ?sportLabel .
  FILTER(LANG(?sportLabel) = 'en')
}

SELECT DISTINCT ?sportLabel WHERE {
  ?record wdt:P31 wd:Q16521 ; # instance of sport record
          wdt:P1346 ?sport ;
          wdt:P585 ?date ;
          wdt:P710 ?athlete .
  ?athlete wdt:P21 wd:Q6581072 . # female
  ?sport wdt:P279* / rdfs:label ?sportLabel .
  FILTER(YEAR(?date) = 1982)
  FILTER(LANG(?sportLabel) = 'en')
  FILTER(CONTAINS(LCASE(?sportLabel), 'hammer') || CONTAINS(LCASE(?sportLabel), 'weight') || CONTAINS(LCASE(?sportLabel), 'throw'))
  MINUS { ?sport wdt:P279* wd:Q178108 } # exclude javelin throw
}
LIMIT 1
